class Solution:
    def waysToReachTarget(self, target, types):
        from functools import lru_cache
        MOD = 10 ** 9 + 7
        types_t = tuple(tuple(t) for t in types)
        @lru_cache(None)
        def solve(i, remaining):
            if remaining == 0:
                return 1
            if i == len(types_t):
                return 0
            cnt, mark = types_t[i]
            total = 0
            for t in range(0, min(cnt, remaining // mark) + 1):
                total += solve(i + 1, remaining - t * mark)
            return total % MOD
        result = solve(0, target) % MOD
        solve.cache_clear()
        return result

