class Solution:
    def waysToReachTarget(self, target, types):
        MOD = 10 ** 9 + 7
        dp = [0] * (target + 1)
        dp[0] = 1
        for cnt, mark in types:
            ndp = [0] * (target + 1)
            for j in range(target + 1):
                total = 0
                max_t = min(cnt, j // mark)
                for t in range(0, max_t + 1):
                    total += dp[j - t * mark]
                ndp[j] = total % MOD
            dp = ndp
        return dp[target]

